{"element_id":"7349cd7","elType":"widget","widgetType":"html","settings":{"html":"<style>
.home-2026-hero-blob{position:absolute;filter:blur(44px);opacity:.55;z-index:0;pointer-events:none;}
.home-2026-hero-blob.b1{width:220px;height:220px;right:-46px;top:-40px;background:rgba(240,107,26,.24);border-radius:999px;}
/* Removed bottom blob to keep the image border consistent */
.home-2026-hero-blob.b2{display:none;}
.home-2026-hero-float{position:absolute;left:-24px;bottom:-18px;max-width:285px;z-index:2;backdrop-filter:blur(14px);-webkit-backdrop-filter:blur(14px);background:rgba(255,255,255,.82);border:1px solid rgba(255,255,255,.6);border-radius:20px;box-shadow:0 14px 35px rgba(20,20,20,.12);padding:16px 16px 14px;}
.home-2026-hero-float .hdr{display:flex;align-items:center;gap:10px;margin-bottom:8px;}
.home-2026-hero-float .ico{width:34px;height:34px;border-radius:999px;background:rgba(255,219,202,.95);display:flex;align-items:center;justify-content:center;font-size:15px;flex:0 0 auto;}
.home-2026-hero-float .t{font-weight:800;font-size:20px;color:#231a15;line-height:1.05;}
.home-2026-hero-float .d{font-size:14px;color:#564339;line-height:1.3;margin:0 0 10px;}
.home-2026-hero-float .btm{display:flex;align-items:center;justify-content:space-between;gap:10px;}
.home-2026-hero-float .price{font-weight:800;color:#F06B1A;font-size:14px;white-space:nowrap;}
.home-2026-hero-float .badge{font-size:10px;font-weight:800;letter-spacing:.08em;text-transform:uppercase;background:rgba(0,109,55,.10);color:#006d37;padding:4px 8px;border-radius:999px;white-space:nowrap;}
@media (max-width:767px){
  .home-2026-hero-float{left:8px;right:8px;bottom:8px;max-width:none;padding:12px;}
  .home-2026-hero-float .t{font-size:17px;}
  .home-2026-hero-float .d{font-size:12px;}
}
</style>
<div class="home-2026-hero-blob b1"></div>
<div class="home-2026-hero-float">
  <div class="hdr">
    <div class="ico">🍽️</div>
    <div class="t">Chefs Special</div>
  </div>
  <p class="d">Maharaja Thali (Non-veg)  Combination of 7 items</p>
  <div class="btm">
    <div class="price">From $15.00 CAD</div>
    <div class="badge">High Protein</div>
  </div>
</div>"}}
